/*--- MAIN STYLES ---*/
html {
    height: 100%;
    width: 100%;
}

body {
    box-sizing: border-box;
    user-select: none;

    background-color: #333;
    color: white;

    margin: 0;
    height: fit-content;
    text-align: center;
}

a {
    text-decoration: none;
    color: white;
}

ul {
    list-style-type: none;
    font-size: 12px;
    font-weight: bold;
    margin: 0;
    padding: 0;
}

img {
    max-width: 100%;
    max-height: 100%;
}

/*--- HEADER ---*/
#header {
    position: sticky;
    top: 0;

    background-color: black;
    
    height: fit-content;
    max-height: 90px;
    width: 100%;
    margin-bottom: 0;
    
    z-index: 999;
}

#header > h1 {
    margin: 0px;
}

/*--- CONTENT ---*/
#container {
    display: flex;
    box-sizing: border-box;

    width: 100%;

    background-image: url("/f869a70e987ddd79baa6cf9fecde4b56.jpeg");
    background-repeat: round;    
}

/*--- LEFT SIDE ---*/
#personal {
    box-sizing: border-box;
    font-size: 18px;
    width: 40%;
    margin: auto;
    border-right: dashed 3px red; 
}

#description {
    width: 80%;
    margin: auto;
}

#techstack {
    display: flex;
    flex-wrap: wrap;
    gap: 20px;
    justify-content: center;
}

img.skillIcon {
    width: 35px;
    height: 35px;
}

#check {
    color: red;
}

#check:hover {
    font-size: 20px;
}

#check::after {
    content: " ON THE RIGHT!";
}

/*--- RIGHT SIDE ---*/
#achievements {
    box-sizing: border-box;
    width: 60%;
    height: fit-content;
    margin: auto;
}

#mainProject {
    box-sizing: border-box;

    min-height: 200px;
    height: 600px;
    min-width: 200px;
    max-width: 70%;
    margin: auto;
    margin-top: 10px;

    box-shadow: 0px 0px 45px white;
}

#mainProject:hover {
    transform: translateX(10px);
}

#mainProjectName {
    font-size: 35px;
    letter-spacing: 2px;
    margin-top: 0px;
    margin-bottom: 0px;
}

#mainProjectIMG {
    max-height: 400px;
    width: 400px;
    max-width: 100%;
    margin: auto;  
}

#mainProjectVID {
    min-height: 350px;
    max-height: 400px;
    width: 600px;
    max-width: 100%;
    margin: auto;
    transition: opacity 0.5s;
}

video {
    width: 100%;
} 

#mainProjectVID.minOpacity {
    opacity: 0;
}

#mainProjectVID.maxOpacity {
    opacity: 1;
}

#mainProjectDescription {
    font-size: 18px;
    min-height: 50px;
}

#mainProjectSkills {
    list-style-type: square;
    font-size: 20px;

    width: 40%;
    margin: auto;
    margin-top: 0;
}

#projects {
    box-sizing: border-box;
    display: flex;
    align-items: center;
    justify-content: center;
    
    min-width: 200px;
    max-width: 420px;
    margin: auto;
    margin-top: 15px;
    margin-bottom: 10px;
}

.project {
    cursor: pointer;

    width: 100px;
    height: 100px;

    z-index: 1;
    opacity: 0.5;
}

.project > img {
    border-radius: 15px;
}

.project:nth-child(2) {
    height: 130px;
    width: 130px;
    transform: translateX(-5%);

    z-index: 99;
    opacity: 1;
}

.project:nth-child(2) > img {
    max-height: 110%;  
    max-width: 110%;
}

/*--- FOOTER ---*/
#footer {
    display: flex;
    flex-direction: row;
    gap: 60px;
    justify-content: center;

    position: sticky;
    bottom: 0;

    background-color: gray;
    
    margin-top: 5px;
    padding: 5px;
    
    z-index: 999;
}

#footer > h2 {
    margin-bottom: 0;
}

.contact {
    max-height: 50px;
}

.contact > a {
    color: white;
}

img.contactIcon {
    width: 30px;
    height: 30px;
}

@media screen and (max-width: 800px) {
    #mainProjectVID {
        min-height: 250px;
    }
}

@media screen and (max-width: 500px) {
    h1 {
        font-size: 14px;
    }

    h2 {
        font-size: 12px;
    }

    h3 {
        font-size: 11px;
    }

    #header {
        max-height: 50px;
    }

    #container {
        display: block;
    }

    #personal, #achievements {
        font-size: 10px;
        width: 100%;
    }

    #personal {
        border-right: none;
        border-bottom:  dashed 2px red; 
    }

    img.skillIcon {
        height: 25px;
        width: 25px;
    }

    #check::after {
        content: " BELOW!";
    }

