        font-size: 8px;
    }

    #mainProject {
        height: fit-content;
        min-width: 50%;
        max-width: 100%;
    }

    #mainProject:hover {
        transform: none;
    }

    #mainProjectName {
        font-size: 25px;
    }

    #mainProjectVID {
        max-height: 300px;
        min-height: 220px;
    }

    #mainProjectDescription {
        font-size: 10px;
    }

    #mainProjectSkills {
        font-size: 12px;
        width: 55%;
    }

    #projects {
        height: 100%;
        min-width: 50%;
        max-width: 100%;  
    }

    .project {
        height: fit-content;
    }
    
    .project:nth-child(2) {
        height: fit-content;
    }

    .project > img {
        border-radius: 10px;
    }

    img.contactIcon {
        height: 18px;
        width: 18px;
    }
    
    .contact > a {
        font-size: 8px;
    }
}

@media screen and (max-width: 300px) { 
    #footer {
        flex-direction: column;
        gap: 0;
    }
}

@media screen and (max-width: 200px) {
    h1 {
        font-size: 10px;
    }

    h2 {
        font-size: 9px;
    }

    h3 {
        font-size: 8px;
    }

    #mainProjectName {
        font-size: 14px;
    }

    #mainProjectVID {
        min-height: 100px;
        max-height: 200px;
    }

    img.contactIcon {
        height: 15px;
        width: 15px; 
    }

    .contact {
        font-size: 5px;
    }

    .contact > a {
        font-size: 5px;
    }
}

